
import React, { useState, useEffect } from "react";


import {   DropDwnSearchPicker_Cmpt } from "../../../components";
import {  	ObjectKeys,  txtOrempty,  } from "../../../stores/Utils";


import {  search_notary_cl } from "../services/customer_fetch_service";


const DropDwnSearchPicker = DropDwnSearchPicker_Cmpt();






 
const PickPerson  = ({ init, emptyLabel, onSelect }) => {

	const [list, setList] = useState([]);

	const parseD =  (v) => {
		let nA = []
		v && ObjectKeys(v).map(cl=>{
			let fullNm = txtOrempty(v[cl]?.firstName) + txtOrempty(v[cl]?.middleName)  + txtOrempty(v[cl]?.lastName);
			nA.push({id:cl, label: fullNm });
		})
		setList(nA);
	}

	const fetch =  (v) => {
		search_notary_cl(v, parseD);
	}

	const clear =  () => {
		setList([]);
	}



	return (
		<div style={{minWidth: 260}}>
			<DropDwnSearchPicker
				lbl_empty={init || emptyLabel} 
				list={list}
				onSelect={(e)=>onSelect(e)} 
				background={"var(--dark-900)"}
				color={"var(--light-200)"}
				callempty={clear}
				fetchData={fetch}
			/>
		</div>
	)

}



export default PickPerson;